firmware_template.source:
#include "freertos_tasks.h"
void task_manager_setup() {
  Serial.printf("[rtos] Free heap: %lu bytes\n", (unsigned long)ESP.getFreeHeap());
  Serial.printf("[rtos] Cores: %d\n", ESP.getChipCores());
}
void task_create(const char* name, void (*fn)(void*), uint32_t stack, int pri, int core) {
  BaseType_t r = xTaskCreatePinnedToCore(fn, name, stack, NULL, pri, NULL, core);
  Serial.printf("[rtos] Task '%s' on core %d: %s\n", name, core, r == pdPASS ? "OK" : "FAIL");
}
void task_delay_ms(uint32_t ms) { vTaskDelay(ms / portTICK_PERIOD_MS); }
uint32_t task_get_free_heap() { return ESP.getFreeHeap(); }
